{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyNBcO11do8hwAeQw/uMuZXO"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"1f47J555K3m8"},"outputs":[],"source":["# ============================================\n","# divident_str.py\n","# Streamlit 版本 - 即時殖利率監視器\n","# 部署於 Streamlit Community Cloud\n","# ============================================\n","\n","import streamlit as st\n","import pandas as pd\n","import shioaji as sj\n","import os\n","import base64\n","import time\n","import requests\n","from io import StringIO\n","from datetime import datetime, timedelta\n","\n","# ============================================\n","# 頁面設定\n","# ============================================\n","st.set_page_config(\n","    page_title=\"即時殖利率排行\",\n","    page_icon=\"📊\",\n","    layout=\"wide\",\n","    initial_sidebar_state=\"expanded\"\n",")\n","\n","# ============================================\n","# 參數設定（可從側邊欄調整）\n","# ============================================\n","DEFAULT_INTERVAL = 30\n","DEFAULT_TOP_N = 0\n","CSV_URL = \"https://raw.githubusercontent.com/你的帳號/你的倉庫/main/divident.csv\"\n","\n","TIME_0900 = datetime.strptime(\"09:00\", \"%H:%M\").time()\n","TIME_1330 = datetime.strptime(\"13:30\", \"%H:%M\").time()\n","\n","# ============================================\n","# 快取函式：避免重複載入\n","# ============================================\n","@st.cache_data(ttl=60)\n","def load_csv_from_github():\n","    \"\"\"從 GitHub 讀取 divident.csv\"\"\"\n","    try:\n","        response = requests.get(CSV_URL)\n","        response.raise_for_status()\n","\n","        content = response.text\n","        df = pd.read_csv(StringIO(content), dtype={'code': str})\n","        df = df.dropna(how='all')\n","\n","        df['ex_date'] = df['ex_date'].astype(str).str.strip().replace('', None)\n","        df['ex_date_dt'] = pd.to_datetime(df['ex_date'], errors='coerce').dt.date\n","        df['dividend'] = df['dividend'].fillna(0)\n","\n","        return df\n","\n","    except Exception as e:\n","        st.error(f\"讀取 CSV 失敗: {e}\")\n","        return None\n","\n","@st.cache_resource\n","def login_shioaji():\n","    \"\"\"登入 Shioaji（快取，只登入一次）\"\"\"\n","    try:\n","        api = sj.Shioaji()\n","\n","        api_key = os.environ.get(\"API_KEY\")\n","        secret_key = os.environ.get(\"SECRET_KEY\")\n","        ca_pass = os.environ.get(\"CA_PASS\")\n","\n","        if not api_key or not secret_key:\n","            st.error(\"環境變數未設定（API_KEY / SECRET_KEY）\")\n","            return None\n","\n","        api.login(api_key=api_key, secret_key=secret_key)\n","\n","        # 憑證（從環境變數 Base64 還原）\n","        ca_base64 = os.environ.get(\"CA_BASE64\")\n","        if ca_base64:\n","            ca_data = base64.b64decode(ca_base64)\n","            ca_path = \"/tmp/Sinopac.pfx\"\n","            with open(ca_path, \"wb\") as f:\n","                f.write(ca_data)\n","            api.activate_ca(ca_path=ca_path, ca_passwd=ca_pass)\n","\n","        return api\n","\n","    except Exception as e:\n","        st.error(f\"登入失敗: {e}\")\n","        return None\n","\n","# ============================================\n","# 輔助函式\n","# ============================================\n","def get_trading_mode():\n","    \"\"\"判斷盤中/盤後\"\"\"\n","    now = datetime.now()\n","    current_time = now.time()\n","    is_weekday = now.weekday() < 5\n","    is_trading_hours = is_weekday and (current_time >= TIME_0900 and current_time <= TIME_1330)\n","\n","    if is_trading_hours:\n","        return \"realtime\"\n","    else:\n","        return \"single\"\n","\n","def build_contracts(api, df):\n","    \"\"\"建立合約清單\"\"\"\n","    contracts = []\n","    for code in df['code']:\n","        try:\n","            code_str = str(code)\n","            stock = None\n","            try:\n","                stock = api.Contracts.Stocks[code_str]\n","            except:\n","                try:\n","                    stock = api.Contracts.Stocks[(code_str, 'OTC')]\n","                except:\n","                    pass\n","            if stock:\n","                contracts.append(stock)\n","        except:\n","            pass\n","    return contracts\n","\n","def fetch_prices(api, contracts):\n","    \"\"\"取得股價\"\"\"\n","    price_map = {}\n","    name_map = {}\n","\n","    if not contracts:\n","        return price_map, name_map\n","\n","    try:\n","        snapshots = api.snapshots(contracts)\n","        if snapshots:\n","            for s in snapshots:\n","                code = str(getattr(s, 'code', ''))\n","                if not code:\n","                    continue\n","\n","                price = None\n","                if hasattr(s, 'close') and s.close:\n","                    price = s.close\n","                elif hasattr(s, 'price') and s.price:\n","                    price = s.price\n","                elif hasattr(s, 'bid') and s.bid:\n","                    price = s.bid\n","                elif hasattr(s, 'ask') and s.ask:\n","                    price = s.ask\n","                price_map[code] = price\n","\n","                shioaji_name = None\n","                if hasattr(s, 'name') and s.name:\n","                    shioaji_name = s.name\n","                elif hasattr(s, 'code_name') and s.code_name:\n","                    shioaji_name = s.code_name\n","\n","                if not shioaji_name:\n","                    try:\n","                        stock = api.Contracts.Stocks[code]\n","                        shioaji_name = stock.name if hasattr(stock, 'name') else code\n","                    except:\n","                        shioaji_name = code\n","\n","                name_map[code] = shioaji_name\n","    except Exception as e:\n","        st.warning(f\"取得股價失敗: {e}\")\n","\n","    return price_map, name_map\n","\n","def calculate_yield(df, price_map, name_map, top_n=0):\n","    \"\"\"計算殖利率\"\"\"\n","    df_copy = df.copy()\n","    df_copy['price'] = df_copy['code'].map(price_map)\n","    df_copy['name'] = df_copy['code'].map(name_map)\n","    df_copy['name'] = df_copy['name'].fillna(df_copy['code'])\n","\n","    df_copy['yield'] = df_copy.apply(\n","        lambda row: row['dividend'] / row['price'] * 100\n","        if row['price'] and row['price'] > 0 and row['dividend'] > 0 else 0,\n","        axis=1\n","    )\n","\n","    df_result = df_copy.sort_values('yield', ascending=False)\n","    df_result['ex_date_display'] = df_result['ex_date'].fillna('未定')\n","\n","    output_cols = ['code', 'name', 'dividend', 'price', 'yield', 'ex_date_display']\n","    df_output = df_result[output_cols].copy()\n","    df_output.columns = ['代碼', '名稱', '股利', '股價', '殖利率(%)', '除息日']\n","\n","    df_output['股利'] = df_output['股利'].round(2)\n","    df_output['股價'] = df_output['股價'].round(2)\n","    df_output['殖利率(%)'] = df_output['殖利率(%)'].round(2)\n","\n","    if top_n > 0:\n","        df_output = df_output.head(top_n)\n","\n","    return df_output\n","\n","# ============================================\n","# 主程式\n","# ============================================\n","def main():\n","    # ===== 側邊欄 =====\n","    with st.sidebar:\n","        st.header(\"⚙️ 設定\")\n","\n","        update_interval = st.slider(\n","            \"⏱️ 更新間隔（秒）\",\n","            min_value=10,\n","            max_value=60,\n","            value=DEFAULT_INTERVAL,\n","            step=5,\n","            help=\"盤中自動更新的間隔\"\n","        )\n","\n","        top_n = st.number_input(\n","            \"📊 顯示前 N 筆\",\n","            min_value=0,\n","            value=DEFAULT_TOP_N,\n","            step=5,\n","            help=\"0 表示全部顯示\"\n","        )\n","\n","        st.divider()\n","\n","        if st.button(\"🔄 強制更新\", use_container_width=True):\n","            st.session_state.force_update = True\n","            st.rerun()\n","\n","        st.divider()\n","\n","        # 狀態顯示\n","        st.caption(\"📌 狀態\")\n","        mode = st.session_state.get(\"mode\", \"未知\")\n","        mode_icon = \"🟢\" if mode == \"realtime\" else \"🔵\"\n","        st.write(f\"{mode_icon} 模式: {mode}\")\n","\n","        last_update = st.session_state.get(\"last_update\", \"---\")\n","        st.write(f\"🕐 最後更新: {last_update}\")\n","\n","    # ===== 主內容 =====\n","    st.title(\"📊 即時殖利率排行\")\n","    st.caption(\"台股除息監視器\")\n","\n","    # ===== 登入 =====\n","    api = login_shioaji()\n","    if api is None:\n","        st.error(\"❌ 登入失敗，請檢查環境變數\")\n","        return\n","\n","    # ===== 讀取 CSV =====\n","    df = load_csv_from_github()\n","    if df is None:\n","        st.error(\"❌ 讀取資料失敗\")\n","        return\n","\n","    # ===== 建立合約 =====\n","    contracts = build_contracts(api, df)\n","    if not contracts:\n","        st.warning(\"⚠️ 無有效合約，請檢查股票代碼\")\n","        return\n","\n","    # ===== 取得資料 =====\n","    with st.spinner(\"📊 正在更新資料...\"):\n","        price_map, name_map = fetch_prices(api, contracts)\n","        df_output = calculate_yield(df, price_map, name_map, top_n)\n","\n","    # ===== 判斷模式 =====\n","    has_data = any(p is not None for p in price_map.values())\n","    current_mode = get_trading_mode()\n","\n","    if has_data and current_mode == \"realtime\":\n","        mode = \"realtime\"\n","    else:\n","        mode = \"single\"\n","\n","    st.session_state.mode = mode\n","    st.session_state.last_update = datetime.now().strftime(\"%H:%M:%S\")\n","\n","    # ===== 顯示統計 =====\n","    col1, col2, col3, col4 = st.columns(4)\n","\n","    with col1:\n","        st.metric(\"📊 總筆數\", len(df_output))\n","    with col2:\n","        valid_count = len(df_output[df_output['殖利率(%)'] > 0])\n","        st.metric(\"📈 有殖利率\", valid_count)\n","    with col3:\n","        max_yield = df_output['殖利率(%)'].max()\n","        st.metric(\"🏆 最高殖利率\", f\"{max_yield:.2f}%\" if max_yield > 0 else \"N/A\")\n","    with col4:\n","        mode_icon = \"🟢\" if mode == \"realtime\" else \"🔵\"\n","        mode_text = \"盤中即時\" if mode == \"realtime\" else \"盤後單次\"\n","        st.metric(\"📌 模式\", f\"{mode_icon} {mode_text}\")\n","\n","    # ===== 顯示表格 =====\n","    st.dataframe(\n","        df_output,\n","        use_container_width=True,\n","        column_config={\n","            \"代碼\": st.column_config.TextColumn(\"代碼\", width=\"small\"),\n","            \"名稱\": st.column_config.TextColumn(\"名稱\", width=\"medium\"),\n","            \"股利\": st.column_config.NumberColumn(\"股利\", format=\"%.2f\"),\n","            \"股價\": st.column_config.NumberColumn(\"股價\", format=\"%.2f\"),\n","            \"殖利率(%)\": st.column_config.NumberColumn(\"殖利率\", format=\"%.2f%%\"),\n","            \"除息日\": st.column_config.TextColumn(\"除息日\", width=\"medium\"),\n","        },\n","        height=600\n","    )\n","\n","    # ===== 底部資訊 =====\n","    if mode == \"realtime\":\n","        st.info(f\"🟢 盤中模式：每 {update_interval} 秒自動更新 | 下次更新：{(datetime.now() + timedelta(seconds=update_interval)).strftime('%H:%M:%S')}\")\n","        time.sleep(update_interval)\n","        st.rerun()\n","    else:\n","        st.info(\"🔵 盤後模式：股價已固定，如需更新請按側邊欄「強制更新」按鈕\")\n","\n","    # 處理強制更新\n","if st.session_state.get(\"force_update\", False):\n","    st.session_state.force_update = False\n","    st.rerun()\n","\n","# ===== 程式入口 =====\n","if __name__ == \"__main__\":\n","    main()"]}]}